import sys
from kafka.admin import KafkaAdminClient, NewTopic

def create_topic(admin_client, topic_name, num_partitions, replication_factor, topic_config):
    topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor, topic_configs=topic_config)
    admin_client.create_topics(new_topics=[topic], validate_only=False)

def main():
    if len(sys.argv) < 5:
        print("Usage: python kafka_admin.py <topic_name> <num_partitions> <replication_factor> <config_key=value>")
        sys.exit(1)

    topic_name = sys.argv[1]
    num_partitions = int(sys.argv[2])
    replication_factor = int(sys.argv[3])
    topic_config = {k: v for arg in sys.argv[4:] for k, v in [arg.split('=')]}
    
    admin_client = KafkaAdminClient(bootstrap_servers='localhost:9092', client_id='kafka_admin')
    
    try:
        create_topic(admin_client, topic_name, num_partitions, replication_factor, topic_config)
        print(f"Topic '{topic_name}' created successfully.")
    except Exception as e:
        print(f"Failed to create topic '{topic_name}': {e}")
    finally:
        admin_client.close()

if __name__ == "__main__":
    main()